const createChoice = (id: string, text: string, feedback: string, tagEffects: any) => ({
  id, text, feedback, tagEffects,
});

const createStep = (stepNumber: number, scenario: string, question: string, choices: any[]) => ({
  id: `step_${stepNumber}`, stepNumber, scenario, question, choices,
});

